CREATE TABLE public.app_settings ( id bigint NOT NULL, booksy_happy_hours integer NOT NULL, boost_net_rate integer NOT NULL, google_review_discount integer NOT NULL, visit_absence_rate integer NOT NULL, visit_vip_rate integer NOT NULL, voucher_expiry_time integer NOT NULL );
ALTER TABLE public.app_settings ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.app_settings_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.audit_log ( id bigint NOT NULL, action character varying(255) NOT NULL, browser_name character varying(255), changed_fields character varying(255), device_type character varying(255), entity_id bigint NOT NULL, entity_key_trait character varying(255), entity_type character varying(255) NOT NULL, ip_address character varying(255), new_value text, old_value text, performed_by character varying(255) NOT NULL, session_id character varying(255), "timestamp" timestamp(6) without time zone NOT NULL, CONSTRAINT audit_log_action_check CHECK (((action)::text = ANY ((ARRAY['CREATE'::character varying, 'UPDATE'::character varying, 'DELETE'::character varying])::text[]))) );
ALTER TABLE public.audit_log ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.audit_log_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.bonus_params_snapshot ( id bigint NOT NULL, bonus_percent double precision, bonus_threshold double precision, boost_net_rate double precision, created_at timestamp(6) without time zone NOT NULL, month integer NOT NULL, sale_bonus_percent double precision, year integer NOT NULL, employee_id bigint NOT NULL );
ALTER TABLE public.bonus_params_snapshot ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.bonus_params_snapshot_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.brand ( id bigint NOT NULL, name character varying(255) NOT NULL );
ALTER TABLE public.brand ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.brand_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.cash_ledger ( id bigint NOT NULL, cash_out_amount double precision NOT NULL, closing_amount double precision, date date NOT NULL, deposit double precision NOT NULL, is_closed boolean NOT NULL, note text, opening_amount double precision NOT NULL, closed_by_id bigint, created_by_id bigint NOT NULL );
ALTER TABLE public.cash_ledger ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.cash_ledger_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.client ( id bigint NOT NULL, boost_client boolean NOT NULL, created_by_user_id bigint, first_name character varying(255) NOT NULL, is_deleted boolean NOT NULL, last_name character varying(255) NOT NULL, phone_number character varying(255), red_flag boolean NOT NULL, signed_regulations boolean NOT NULL, discount_id bigint );
CREATE TABLE public.client_debt ( id bigint NOT NULL, created_at date, created_by_user_id bigint, payment_status character varying(255) NOT NULL, type character varying(255) NOT NULL, value double precision NOT NULL, client_id bigint NOT NULL, visit_id bigint, CONSTRAINT client_debt_payment_status_check CHECK (((payment_status)::text = ANY ((ARRAY['PAID'::character varying, 'PARTIAL'::character varying, 'UNPAID'::character varying])::text[]))), CONSTRAINT client_debt_type_check CHECK (((type)::text = ANY ((ARRAY['ABSENCE_FEE'::character varying, 'PARTIAL_PAYMENT'::character varying, 'UNPAID'::character varying])::text[]))) );
ALTER TABLE public.client_debt ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.client_debt_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
ALTER TABLE public.client ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.client_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.client_note ( id bigint NOT NULL, content character varying(255) NOT NULL, created_at date NOT NULL, created_by_user_id bigint, client_id bigint NOT NULL, created_by_id bigint NOT NULL );
ALTER TABLE public.client_note ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.client_note_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.company_expense ( id bigint NOT NULL, category character varying(255) NOT NULL, expense_date date NOT NULL, invoice_number character varying(255), source character varying(255) NOT NULL, total_net double precision NOT NULL, total_value double precision NOT NULL, total_vat double precision NOT NULL, order_id bigint, CONSTRAINT company_expense_category_check CHECK (((category)::text = ANY ((ARRAY['RENT'::character varying, 'FEES'::character varying, 'ZUS'::character varying, 'EQUIPMENT'::character varying, 'SALARY'::character varying, 'PRODUCTS'::character varying, 'UNRELATED'::character varying, 'OTHER'::character varying])::text[]))) );
ALTER TABLE public.company_expense ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.company_expense_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.company_expense_item ( id bigint NOT NULL, name character varying(255) NOT NULL, price double precision NOT NULL, quantity integer NOT NULL, vat_rate character varying(255) NOT NULL, company_expense_id bigint NOT NULL, CONSTRAINT company_expense_item_vat_rate_check CHECK (((vat_rate)::text = ANY ((ARRAY['VAT_23'::character varying, 'VAT_8'::character varying, 'VAT_7'::character varying, 'VAT_5'::character varying, 'VAT_0'::character varying, 'VAT_ZW'::character varying, 'VAT_NP'::character varying])::text[]))) );
ALTER TABLE public.company_expense_item ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.company_expense_item_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
