CREATE TABLE public.employee ( id bigint NOT NULL, bonus_percent double precision, employment_type character varying(255) NOT NULL, is_deleted boolean NOT NULL, last_name character varying(255) NOT NULL, name character varying(255) NOT NULL, sale_bonus_percent double precision, CONSTRAINT employee_bonus_percent_check CHECK (((bonus_percent <= (100)::double precision) AND (bonus_percent >= (0)::double precision))), CONSTRAINT employee_employment_type_check CHECK (((employment_type)::text = ANY ((ARRAY['QUARTER'::character varying, 'HALF'::character varying, 'THREE_QUARTERS'::character varying, 'FULL'::character varying])::text[]))), CONSTRAINT employee_sale_bonus_percent_check CHECK (((sale_bonus_percent <= (100)::double precision) AND (sale_bonus_percent >= (0)::double precision))) );
ALTER TABLE public.employee ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.employee_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.internal_order ( id bigint NOT NULL, order_date date NOT NULL, order_number bigint NOT NULL, shipping_cost double precision NOT NULL, total_net double precision NOT NULL, total_value double precision NOT NULL, total_vat double precision NOT NULL, supplier_id bigint NOT NULL );
ALTER TABLE public.internal_order ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.internal_order_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.inventory_report ( id bigint NOT NULL, approved boolean NOT NULL, created_at date NOT NULL, created_by bigint NOT NULL );
ALTER TABLE public.inventory_report ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.inventory_report_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.inventory_report_item ( id bigint NOT NULL, supply_after integer NOT NULL, supply_before integer NOT NULL, inventory_report_id bigint NOT NULL, product_id bigint NOT NULL, CONSTRAINT inventory_report_item_supply_after_check CHECK ((supply_after >= 0)) );
ALTER TABLE public.inventory_report_item ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.inventory_report_item_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.order_product ( id bigint NOT NULL, name character varying(255) NOT NULL, price double precision NOT NULL, quantity integer NOT NULL, vat_rate character varying(255) NOT NULL, order_id bigint NOT NULL, product_id bigint NOT NULL, CONSTRAINT order_product_vat_rate_check CHECK (((vat_rate)::text = ANY ((ARRAY['VAT_23'::character varying, 'VAT_8'::character varying, 'VAT_7'::character varying, 'VAT_5'::character varying, 'VAT_0'::character varying, 'VAT_ZW'::character varying, 'VAT_NP'::character varying])::text[]))) );
ALTER TABLE public.order_product ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.order_product_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.payment ( id bigint NOT NULL, amount double precision NOT NULL, method character varying(255) NOT NULL, voucher_id bigint, visit_id bigint, CONSTRAINT payment_method_check CHECK (((method)::text = ANY ((ARRAY['CASH'::character varying, 'CARD'::character varying, 'BLIK'::character varying, 'TRANSFER'::character varying, 'VOUCHER'::character varying])::text[]))) );
ALTER TABLE public.payment ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.payment_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.product ( id bigint NOT NULL, description character varying(255), fallback_net_purchase_price double precision, fallback_vat_rate character varying(255), is_deleted boolean NOT NULL, name character varying(255) NOT NULL, selling_price double precision, supply integer NOT NULL, unit character varying(255), vat_rate character varying(255) NOT NULL, volume integer, brand_id bigint NOT NULL, category_id bigint NOT NULL, CONSTRAINT product_fallback_vat_rate_check CHECK (((fallback_vat_rate)::text = ANY ((ARRAY['VAT_23'::character varying, 'VAT_8'::character varying, 'VAT_7'::character varying, 'VAT_5'::character varying, 'VAT_0'::character varying, 'VAT_ZW'::character varying, 'VAT_NP'::character varying])::text[]))), CONSTRAINT product_unit_check CHECK (((unit)::text = ANY ((ARRAY['ML'::character varying, 'G'::character varying])::text[]))), CONSTRAINT product_vat_rate_check CHECK (((vat_rate)::text = ANY ((ARRAY['VAT_23'::character varying, 'VAT_8'::character varying, 'VAT_7'::character varying, 'VAT_5'::character varying, 'VAT_0'::character varying, 'VAT_ZW'::character varying, 'VAT_NP'::character varying])::text[]))) );
CREATE TABLE public.product_category ( id bigint NOT NULL, color character varying(255) NOT NULL, name character varying(255) NOT NULL );
ALTER TABLE public.product_category ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.product_category_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
ALTER TABLE public.product ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.product_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
CREATE TABLE public.review ( id bigint NOT NULL, created_by_user_id bigint, is_used boolean NOT NULL, issue_date date NOT NULL, source character varying(255) NOT NULL, client_id bigint NOT NULL, CONSTRAINT review_source_check CHECK (((source)::text = ANY ((ARRAY['BOOKSY'::character varying, 'GOOGLE'::character varying])::text[]))) );
ALTER TABLE public.review ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY ( SEQUENCE NAME public.review_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 );
